/**
 * Story 198. `navigator.serviceWorker.ready` never settles when the service
 * worker registration failed or is unavailable — and several callers awaited
 * it directly, so a single failed SW registration could hang a whole screen
 * (the notification-settings subscription lookup) or a debug readout (client-
 * log shipping availability) forever. This bounds the wait: it resolves a
 * registration when one becomes ready in time, or `{registration: null,
 * reason}` when the SW is missing, the wait times out, or `ready` rejects.
 * Callers branch on `registration` and never block indefinitely.
 */
export interface SwReadyResult {
    registration: ServiceWorkerRegistration | null;
    reason?: string;
}

const DEFAULT_SW_READY_TIMEOUT_MS = 3000;

export function swReadyWithTimeout(
    timeoutMs: number = DEFAULT_SW_READY_TIMEOUT_MS,
): Promise<SwReadyResult> {
    const ready = (navigator as { serviceWorker?: { ready?: Promise<ServiceWorkerRegistration> } })
        .serviceWorker?.ready;
    if (typeof navigator === 'undefined' || !navigator.serviceWorker || typeof ready?.then !== 'function') {
        return Promise.resolve({
            registration: null,
            reason: 'Service Worker is not available in this context',
        });
    }

    let timer: ReturnType<typeof setTimeout> | undefined;
    const timeout = new Promise<SwReadyResult>((resolve) => {
        timer = setTimeout(
            () => resolve({
                registration: null,
                reason: `navigator.serviceWorker.ready did not settle within ${timeoutMs}ms`,
            }),
            timeoutMs,
        );
    });

    // `.catch` here (rather than a try/catch around the race) keeps a late
    // rejection from escaping as an unhandled rejection after the timeout wins.
    const readyResult: Promise<SwReadyResult> = ready
        .then((registration) => ({ registration }))
        .catch((error) => ({
            registration: null,
            reason: error instanceof Error ? error.message : String(error),
        }));

    return Promise.race([readyResult, timeout]).finally(() => {
        if (timer !== undefined) clearTimeout(timer);
    });
}
